#include <gtest/gtest.h>

#include "solvers/subsetFinder.h"

TEST(TestHiddenPair, HiddenPair1) {
    // 1,9 in r15c8 => r15c8<>8.in
    Inst inst = {0x34, 0x07, 0x00, 0x47, 0x08, 0x07, 0x07, 0x47, 0x07};
    std::vector<uint16_t> executees = {0x0707, 0x4707};
    Grid grid(
        "0700000000000011100000001600000000001500000000000001100000000400000000"
        "0000001000010000100000011000101000011000011110000019000000000018000000"
        "0000010000000000000110000000160000000000000010100000170000000000000011"
        "1000000010111000000010111000000010111000000800000000001700000000001900"
        "0000000012000000000000000101000000101111000000011000010017000000000019"
        "0000000000040000000000110000000000050000000000000010010100000100010100"
        "0001100001000010011001000010011000000010011000001200000000001600000000"
        "0013000000000000000000110000100000011000100000111000111001000000111001"
        "0000001010000000090000000000180000000000070000000000140000000000150000"
        "0000000011100000000900000000000000001100001200000000001300000000001400"
        "0000000001000000000000000011110000000001010000000010100000100101000018"
        "0000000000001001000000170000000000050000000000020000000000190000000000"
        "1300000000000000010100000000101000000000111000000700000000000600000000"
        "00090000000000180000000000110000000000000101000000000100100000");
    findHiddenSubset(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode, false);
    EXPECT_EQ(grid.execution.executees, executees);
}

