TEST(TestHiddenTriple, HiddenTriple1) {
    // Hidden Triple: 2,3,8 in r7c79,r9c9 => r7c7<>4, r7c7<>9, r7c9<>1
    Inst inst = {0x35, 0x66, 0x01, 0x68, 0x02, 0x88, 0x07, 0x66, 0x03,0x66,0x08,0x68,0x00};
    std::vector<uint16_t> executees = {0x6603, 0x6608,0x6800};
    Grid grid("");
    findHiddenSubset(grid, 3);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode, false);
    EXPECT_EQ(grid.execution.executees, executees);
}

